#include <stdio.h>
#include <string.h>

int isVowel(char c){
    return c=='A'||c=='E'||c=='I'||c=='O'||c=='U';
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    const char *target = "CODETOWN";
    char s[16];
    while(T--){
        scanf("%s",s);
        int ok=1;
        for(int i=0;i<8;i++){
            if(isVowel(s[i])!=isVowel(target[i])){ok=0;break;}
        }
        puts(ok?"YES":"NO");
    }
    return 0;
}

